import React from 'react';
import './Navbar.css';

// Consolidated to 5 nav items per brief item #13 / #18
const links = [
  { label: 'About',     href: '#about' },
  { label: 'Tours',     href: '#tours' },
  { label: 'Locations', href: '#locations' },
  { label: 'Gallery',   href: '#gallery' },
  { label: 'Contact',   href: '#contact' },
];

// DGS Peacock Bass logo mark — inline SVG so it renders without external assets
function PeacockBassLogo() {
  return (
    <svg className="dgs-logo-mark" viewBox="0 0 64 64" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
      <defs>
        <linearGradient id="dgsBody" x1="0" y1="0" x2="1" y2="0">
          <stop offset="0%" stopColor="#D4891A"/>
          <stop offset="100%" stopColor="#EF9F27"/>
        </linearGradient>
      </defs>
      {/* Fish body */}
      <path d="M6 32 Q14 18 30 18 Q44 18 52 26 L60 22 L58 32 L60 42 L52 38 Q44 46 30 46 Q14 46 6 32 Z"
            fill="url(#dgsBody)" stroke="#0B3D2E" strokeWidth="1.5"/>
      {/* Vertical bars (peacock bass markings) */}
      <line x1="22" y1="22" x2="22" y2="42" stroke="#0B3D2E" strokeWidth="2" opacity="0.75"/>
      <line x1="32" y1="20" x2="32" y2="44" stroke="#0B3D2E" strokeWidth="2" opacity="0.75"/>
      <line x1="42" y1="22" x2="42" y2="42" stroke="#0B3D2E" strokeWidth="2" opacity="0.75"/>
      {/* Tail eye spot — signature peacock bass marking */}
      <circle cx="50" cy="40" r="3" fill="#0B3D2E"/>
      <circle cx="50" cy="40" r="1.5" fill="#FAF6EE"/>
      {/* Eye */}
      <circle cx="14" cy="28" r="2" fill="#0B3D2E"/>
      <circle cx="14" cy="28" r="0.8" fill="#FAF6EE"/>
    </svg>
  );
}

export default function Navbar({ scrolled }) {
  return (
    <nav className={`navbar ${scrolled ? 'scrolled' : ''}`}>
      <a className="nav-brand" href="#hero">
        <PeacockBassLogo />
        <div className="nav-brand-text">
          <div className="nav-brand-name">
            Drew's <span>Guide</span> Service
          </div>
          <div className="nav-brand-credential">
            10 Years Orvis Endorsed · Capt Drew Rodriguez
          </div>
        </div>
      </a>
      <ul className="nav-links">
        {links.map(l => (
          <li key={l.label}><a href={l.href}>{l.label}</a></li>
        ))}
      </ul>
      <a className="nav-cta" href="#florida-day-trips">Book Now</a>
    </nav>
  );
}
